import sys

def solve_case(s):
    last = {}
    best = 0
    left = 0
    for i, ch in enumerate(s):
        prev = last.get(ch, -1)
        if prev >= left:
            left = prev + 1
        last[ch] = i
        length = i - left + 1
        if length > best:
            best = length
    return best

def main():
    data = sys.stdin.read().split()
    t = int(data[0])
    out = []
    for i in range(1, t + 1):
        out.append(str(solve_case(data[i])))
    print("\n".join(out))

main()
